import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getLoggedInUser } from "../../auth.js";


function EmployeeOffers() {
  const navigate = useNavigate();
  const user = getLoggedInUser();

  const [offers, setOffers] = useState([]);

  /* ---------------- LOAD OFFERS FOR LOGGED EMPLOYEE ---------------- */
  useEffect(() => {
    const storedOffers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    // show only offers for logged-in employee email
    const myOffers = storedOffers.filter(
      (o) => o.email === user?.email
    );

    setOffers(myOffers);
  }, [user?.email]);

  /* ---------------- ACCEPT / REJECT HANDLER ---------------- */
  const updateOfferStatus = (applicationId, status) => {
    const storedOffers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const updatedOffers = storedOffers.map((o) =>
      String(o.applicationId) === String(applicationId)
        ? { ...o, status }
        : o
    );

    localStorage.setItem(
      "offerLetters",
      JSON.stringify(updatedOffers)
    );

    setOffers(
      updatedOffers.filter((o) => o.email === user?.email)
    );

    alert(`Offer ${status}`);
  };

  /* ---------------- VIEW OFFER ---------------- */
  const viewOffer = (applicationId) => {
    navigate(
      `/dashboard/recruitment/offer-preview/${applicationId}`
    );
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>My Job Offers</h2>

      {offers.length === 0 ? (
        <p>No offers received yet.</p>
      ) : (
        <table className="designation-table">
          <thead>
            <tr>
              <th>S.No</th>
              <th>Job Title</th>
              <th>Salary</th>
              <th>Joining Date</th>
              <th>Location</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {offers.map((o, i) => (
              <tr key={o.applicationId}>
                <td>{i + 1}</td>
                <td>{o.jobTitle}</td>
                <td>₹{o.salary}</td>
                <td>{o.joiningDate}</td>
                <td>{o.location}</td>
                <td>{o.status || "SENT"}</td>

                <td style={{ display: "flex", gap: "10px" }}>
                  <button
                    onClick={() => viewOffer(o.applicationId)}
                  >
                    View
                  </button>

                  {(!o.status || o.status === "SENT") && (
                    <>
                      <button
                        style={{ background: "green", color: "white" }}
                        onClick={() =>
                          updateOfferStatus(
                            o.applicationId,
                            "ACCEPTED"
                          )
                        }
                      >
                        Accept
                      </button>

                      <button
                        style={{ background: "red", color: "white" }}
                        onClick={() =>
                          updateOfferStatus(
                            o.applicationId,
                            "REJECTED"
                          )
                        }
                      >
                        Reject
                      </button>
                    </>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default EmployeeOffers;
